### Load data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)

gs <- readr::read_csv("game_stats.csv")


# function to save table 
gt_save_crop <- function(data, file = NULL, bg = "white", whitespace = 50, zoom = 2, expand = 5) {
  tmp <- tempfile(fileext = ".png")

  # Wrap the gtsave_extra call in a tryCatch to handle errors
  tryCatch({
    gtExtras::gtsave_extra(data, tmp, zoom = zoom, expand = expand)
  }, error = function(e) {
    # If there's an error, try using regular gt::gtsave instead
    message("gtsave_extra failed, trying gt::gtsave...")
    gt::gtsave(data, tmp, zoom = zoom, expand = expand)
  })

  magick::image_read(tmp) |> 
    magick::image_trim() |> 
    magick::image_border(bg, glue::glue('{whitespace}x{whitespace}')) |> 
    magick::image_write(file)
  unlink(tmp)
}
```
:::


### Free throw rate table


::: {.cell}

```{.r .cell-code}
sum_tbl <- gs |> 
  dplyr::filter(
    year > 2021,
    lubridate::month(date) == 11 | (lubridate::month(date) == 12 &
                                      lubridate::day(date) < 29)
  ) |>
  dplyr::mutate(
        fouls = pf + opp_pf
  ) |> 
  dplyr::group_by(team, year) |> 
  dplyr::summarise(
    total_fga = sum(fga),
    total_fta = sum(fta), 
    total_fouls = sum(fouls),
    ftr = total_fta / total_fga * 100
  ) 


sum_tbl |> 
    dplyr::group_by(year) |> 
    dplyr::summarise(
        avg_ftr = mean(ftr)
    )
```

::: {.cell-output .cell-output-stdout}

```
