```{.r .cell-code}
# make the table 
bball_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Free Throw Rate Changes by Season</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Shows the Free Throw Rate percentile for a given value by season.<br>Only games played <em>before</em> December 29 of each season.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)


lookup_values <- seq(30, 40, by = 1)

ptile <- sum_tbl |>
  dplyr::group_by(year) |>
  dplyr::summarise(
    stats = list(
      purrr::map_df(lookup_values, ~tibble::tibble(
        target_ftr = .x,
        percentile = stats::ecdf(ftr)(.x)
      ))
    ),
    .groups = "drop"
  ) |>
  tidyr::unnest(stats) |>
  tidyr::pivot_wider(
    names_from = year, 
    values_from = percentile
  ) |>
  dplyr::rename("FTR" = target_ftr)

ftr_tbl <- ptile |> 
  dplyr::arrange(-FTR) |> 
  gt::gt() |> 
  gtUtils::gt_theme_gtutils() |> 
  gtUtils::gt_column_subheaders(
    `FTR` = list(heading = "FTR", subtitle = "FTA/FGA * 100"),
    `2022` = list(heading = "2021-22", subtitle = "358 teams"),
    `2023` = list(heading = "2022-23", subtitle = "363 teams"),
    `2024` = list(heading = "2023-24", subtitle = "362 teams"),
    `2025` = list(heading = "2024-25", subtitle = "364 teams"),
    `2026` = list(heading = "2025-26", subtitle = "365 teams"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |> 
  gt::fmt_number(
    columns = c(FTR),
    decimals = 1
  ) |>
  gt::fmt_percent(
    columns = c(-FTR),
    decimals = 1
  ) |>
  gt::data_color(
    columns = c(-FTR),
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", "#ffffbf", "#a6d96a", "#1a9641"),
    domain = c(.15, .999),
    alpha = 0.6,
  ) |> 
  gt::tab_header(title = gt::html(bball_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via barttorvik.com | theme via {gtUtils} <br>
        Data only for games played in a given season before December 29<br>
        <hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gt::tab_options(table.width = gt::px(550)) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |> 
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative"),
                    size = gt::px(14)
      )
    ),
    locations = gt::cells_body(
      rows = gt::everything(),
      columns = gt::everything()
    )
  ) |> 
  gt::tab_style(
    style = list(gt::cell_borders(
      sides = c("left", "right", "top", "bottom"),
      color = "black",
      weight = gt::px(2)
    )),
    locations = list(
      gt::cells_body(),
      gt::cells_column_labels(),
      gt::cells_row_groups()
    )
  ) |> 
  gtUtils::gt_border_bars_bottom(c("#0d1e2d", "#c1d6e2",
                                   "#f07e1d"))


gt_save_crop(
  ftr_tbl,
  file = "ftr_tbl.png",
  whitespace = 40,
  bg = "#FFFDF5"
)

ftr_tbl
```

