```{.r .cell-code}
ftr_plot <- sum_tbl |>
  dplyr::mutate(
    year_label = dplyr::case_match(
      year,
      2022 ~ "2021-22\n29.7\n358 teams",
      2023 ~ "2022-23\n31.1\n363 teams",
      2024 ~ "2023-24\n33.1\n362 teams",
      2025 ~ "2024-25\n33.2\n364 teams",
      2026 ~ "2025-26\n35.6\n365 teams"
    )
  ) |>
  ggplot2::ggplot(ggplot2::aes(x = factor(year_label), y = ftr)) +
  ggplot2::geom_jitter(
    ggplot2::aes(color = factor(year)),
    width = 0.2,
    alpha = 0.5,
    size = 2.5,
    show.legend = FALSE
  ) +
  ggplot2::stat_summary(
    fun = mean,
    geom = "line",
    ggplot2::aes(group = 1),
    color = "#2c3e50",
    linewidth = 1.2
  ) +
  ggplot2::stat_summary(
    fun = mean,
    geom = "point",
    shape = 21,
    fill = "#2c3e50",
    color = "white",
    size = 4,
    stroke = 1.5
  ) +
  ggplot2::scale_color_viridis_d(option = "mako",
                                 begin = 0.3,
                                 end = 0.8) +
  ggplot2::scale_x_discrete(position = "top") +
  ggplot2::scale_y_continuous(breaks = seq(15, 55, 5)) +
  ggplot2::labs(
    title = "Free Throw Rate is Rising",
    subtitle = "Shows how average D-I Free Throw Rates are climbing up. \nData for all games played through December 29 of each season.  \n",
    x = "",
    y = "FT Rate (FTR)",
    caption = "FTR = (FTA / FGA) * 100 | data: barttorvik.com  \nViz by Chris at Bless your chart"
  ) +
  ggthemes::theme_fivethirtyeight() +
  ggplot2::theme(
    # text = ggplot2::element_text(family = "mono"),
    plot.title = ggplot2::element_text(
      color = "black",
      face = "bold",
      size = 16
    ),
    plot.subtitle = ggplot2::element_text(size = 11, lineheight = 1.1),
    axis.text.x.top = ggplot2::element_text(
      face = "bold",
      color = "black",
      size = 10
    ),
    axis.text.y = ggplot2::element_text(
      color = "black",
      size = 10
    ),
    legend.position = "none",
    panel.grid.major.x = ggplot2::element_line(color = "#f0f0f0", linewidth = 0.3)
  )

ggplot2::ggsave("ftr_plot.png",
                ftr_plot,
                w = 6.5,
                h = 7.5,
                dpi = 600,
                type = "cairo")

